Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays forever
        var handler = new FakeHandler(neverComplete: true);
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            _testContext.CancellationToken);
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_ThrowsTaskCanceled()
    {
        // Arrange — handler that delays longer than the timeout
        var handler = new FakeHandler(neverComplete: true);
        var fetcher = new DataFetcher(new HttpClient(handler)
        {
            Timeout = TimeSpan.FromMilliseconds(100)
        });

        // Act & Assert
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    /// <summary>Minimal fake handler for deterministic tests.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly bool _neverComplete;

        public FakeHandler(HttpResponseMessage response)
            => _response = response;

        public FakeHandler(bool neverComplete)
            => _neverComplete = neverComplete;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_neverComplete)
            {
                await Task.Delay(Timeout.Infinite, cancellationToken);
            }

            return _response!;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it hangs |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type, not a base class |
| `Assert.ThrowsAsync<T>` (timeout test) | `HttpClient.Timeout` may wrap in `TaskCanceledException` or derived type |
| `CreateLinkedTokenSource` | Links to `TestContext.CancellationToken` so the test still respects `[Timeout]` even when testing manual cancellation |
| `FakeHandler` | Avoids real HTTP calls; `neverComplete` variant blocks until cancelled |
| Sealed class + sealed handler | Performance and design clarity |
